SELECT count(*) FROM offer

    AND product_id = #{productId}
    AND supplier_id = #{supplierId}
    AND offer_type = #{offerType}
    AND current_state = #{stateId}

SELECT id, product_id as "productId", supplier_id as "supplierId", offer_type as "offerType", title, description, original_price as "originalPrice", offer_price as "offerPrice", discount_percent as "discountPercent", start_date as "startDate", end_date as "endDate", max_quantity as "maxQuantity", sold_quantity as "soldQuantity", seller_rating as "sellerRating", current_state as "stateId" FROM offer
AND product_id = #{productId} AND supplier_id = #{supplierId} AND offer_type = #{offerType} AND current_state = #{stateId}
${orderby} ${pagination}

SELECT count(*) FROM offer
WHERE current_state = 'PENDING_APPROVAL'
AND supplier_id = #{supplierId}

SELECT count(*) FROM offer
WHERE current_state = 'LIVE'
AND product_id = #{productId}
